import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin, type OpenClawConfig } from "openclaw/plugin-sdk/core";
import type { PulseBoardAccount, PulseBoardConfig } from "./types.js";

/** Resolved account shape passed through config/gateway/status adapters. */
interface ResolvedPulseBoardAccount {
  accountId: string;
  boardUrl: string;
  apiToken: string;
  username: string;
  configured: boolean;
}

function resolvePulseBoardAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const channels = (cfg.channels ?? {}) as Record<string, unknown>;
  const pbCfg = (channels.pulseboard ?? {}) as Partial<PulseBoardConfig>;
  const aid = accountId ?? "default";
  const account = pbCfg.accounts?.[aid];

  return {
    accountId: aid,
    boardUrl: account?.boardUrl ?? "",
    apiToken: account?.apiToken ?? "",
    username: account?.username ?? "",
    configured: Boolean(account?.boardUrl),
  };
}

function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const channels = (cfg.channels ?? {}) as Record<string, unknown>;
  const pbCfg = (channels.pulseboard ?? {}) as Partial<PulseBoardConfig>;
  const ids = pbCfg.accounts ? Object.keys(pbCfg.accounts) : [];
  return ids.length > 0 ? ids : ["default"];
}

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Connect to PulseBoard bulletin messaging.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: listPulseBoardAccountIds,
      resolveAccount: resolvePulseBoardAccount,
      isConfigured: (account) => account.configured,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[pulseboard:${ctx.account.accountId}] connecting to PulseBoard (${ctx.account.boardUrl || "no URL configured"})`,
        );
        return {
          stop: () => {
            ctx.log?.info(`[pulseboard:${ctx.account.accountId}] disconnected from PulseBoard`);
          },
        };
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, text }) => {
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

